window.__QUIZ_DATA__=[{"id":"theory>Biology>2018>1>a>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Explain briefly how the structure of each of the following cells relate to their functions    Sperms cell;   _____________________________________________________________________________   _____________________________________________________________________________   _____________________________________________________________________________   _____________________________________________________________________________","images":[],"marking_scheme":"It has an acrosome which dissolves the protection coat of the egg cell so that it can penetrate the entire protoplasm and fuse with the nucleus of the ovum, while its mitochondria generate energy needed to propel the sperm and the tail helps to move the spermatozoon.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2018>1>a>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Explain briefly how the structure of each of the following cells relate to their functions  Palisade cell;   ___________________________________________________________________   ___________________________________________________________________   ___________________________________________________________________   ___________________________________________________________________","images":[],"marking_scheme":"They contain chloroplast which contains chlorophyll; chlorophyll absorbs light energy which is needed by green plant to manufacture their food (photosynthesis). It should be noted that chloroplast is found in the leaves of plants; and photosynthesis takes place in the leaves.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2018>1>b","subject":"Biology","year":"2018","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Make drawing, 8cm-10cm long of the front view of the female reproductive system in humans and label fully.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"3"},{"id":"theory>Biology>2018>1>c","subject":"Biology","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State two differences between reproduction in mammals and in amphibians","images":[],"marking_scheme":"MammalsAmphibiansThey exhibit viviparity  They look after their young ones  Fertilization is internalThey exhibit oviparity  They do not look so long after their young ones after birth  Fertilization is external","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>1>d","subject":"Biology","year":"2018","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State two methods of birth control in humans.","images":[],"marking_scheme":"- Withdrawal method  - Intra Uterive Device (IUD)","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>2>a>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name the gases involved in the photosynthesis of a plant.    ________________________________________________","images":[],"marking_scheme":"Carbon (IV) oxide - CO2  Oxygen - O2","marks":"4","difficulty":"1"},{"id":"theory>Biology>2018>2>b>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"State one role each of the gases named in 2 (a)i","images":[],"marking_scheme":"Carbondioxide is needed to react with water in the presence of sunlight to yield Glucose, while oxygen is yielded as a by-product.   Oxygen is given off by plants to the enviroment and this is taken by animals for the purpose of respiration.","marks":"4","difficulty":"1"},{"id":"theory>Biology>2018>2>c>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"What is a variegated leaf?","images":[],"marking_scheme":"A variegated leaf is a leaf that has other colours than green on its surface.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>2>c>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which part of the variegated leaf would test positive when treated with iodine solution?","images":[],"marking_scheme":"The green part","marks":"2","difficulty":"3"},{"id":"theory>Biology>2018>2>c>iii","subject":"Biology","year":"2018","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"State two reasons for the answer in 2(c)(ii)","images":[],"marking_scheme":"The green part is the part where photosynthesis takes  The green part is the part that contains chlorophyl  The green part is the part that contains starch","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>2>c>iv","subject":"Biology","year":"2018","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name one mineral element required by plants for the formation of the part that would test positive in 2(c)(ii)","images":[],"marking_scheme":"Phosphorus","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>2>d","subject":"Biology","year":"2018","type":"Theory","sub_label":"d","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"The table below indicates different methods by which organisms obtain food. Place the following organisms under the headings in the table below:   Human, Mushroom, Venus flytrap, Waterleaf plant, Tapeworm, Elephant grass, Housefly, Lichen, Spirogyra , Rhizopus.  HolozoicParasiticSymbioticSaprophyticAutotrophic","images":[],"marking_scheme":"HolozoicParasiticSymbioticSaprophyticAutotrophic- Human  - Venus Fly Trap  - HouseflyTape worm     Lichen    Mushroom  Rhizopus    Water leaf plant  Elephant grass  Spirogyra","marks":"2","difficulty":"3"},{"id":"theory>Biology>2018>3>a>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Explain briefly the following terms:    Renewable natural resources;","images":[],"marking_scheme":"Renewable Natural Resources  These are natural resources that are renewable once they are used or exhausted. Examples include: rain, animals, plants, water, air, food and soil.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>3>a>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Explain briefly the following terms:  non-renewable natural resources;","images":[],"marking_scheme":"Non-renewable Natural Resources  These are resources which when exhausted can not be replaced or recovered. Examples include: petroleum, coal, tin, copper etc.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>3>b>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Give two examples each of:    Renewable natural resources;","images":[],"marking_scheme":"- Food  - Soil","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>3>b>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Give two examples each of:   non-renewable resources.","images":[],"marking_scheme":"- Petroleum  - Copper","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>3>c","subject":"Biology","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"State five ways of conserving forest.","images":[],"marking_scheme":"- Cutting of trees without destroying the undergrowth  - Encouraging reforestation  - Prevention of bush burning  - Establishment of forest reserves  - Educating the public on the value of forest and the importance of conservation.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2018>3>d","subject":"Biology","year":"2018","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"State four effects of adding animal manure to garden soil","images":[],"marking_scheme":"- It improves the soil structure  - It adds nutrient to the soil  - It regulates the PH of the soil  - It prevents soil erosion.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2018>3>e","subject":"Biology","year":"2018","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Give the possible genotype in humans.","images":[],"marking_scheme":"AO, AB, BO, AB and OO","marks":"3","difficulty":"3"},{"id":"theory>Biology>2018>4>a>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the following terms    gene;","images":[],"marking_scheme":"Genes are hereditary unit or basic units of inheritance that are located on the chromosomes.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2018>4>a>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the following terms   hybrid;","images":[],"marking_scheme":"Hybrid is an offspring from a cross between parents that are genetically different but of the same species.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2018>4>a>iii","subject":"Biology","year":"2018","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the following terms   trait;","images":[],"marking_scheme":"Trait is the inheritable character/attribute/feature possessed by an organism.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2018>4>b","subject":"Biology","year":"2018","type":"Theory","sub_label":"b","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"Two heterozygous yellow flowers are crossed. Using a genetic diagram, state the phenotypic and genotypic ratios of the first filial generation","images":["data:image/png;base64,"],"marking_scheme":"Phenotypic ratio: 3 yellow floral plant  1 non-yellow floral plant  Genotypic ratio: 1 : 2 : 1","marks":"5","difficulty":"3"},{"id":"theory>Biology>2018>4>c","subject":"Biology","year":"2018","type":"Theory","sub_label":"c","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"State four transmittable characters in plants","images":[],"marking_scheme":"- Seed size  - Seed color  - Plant height  - Leaf color","marks":"3","difficulty":"2"},{"id":"theory>Biology>2018>6>a>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Explain briefly chemosynthesis as a mode of nutrition","images":[],"marking_scheme":"Chemosynthesis is an autotrophic mode of nutrition by which living organisms manufacture their food by making use of energy obtained from chemical compounds.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>6>a>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Give two examples of organisms that carry out chemosynthesis","images":[],"marking_scheme":"Sulfur bacteria  Azotobacter  Nitrobacter","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>6>b>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"List three gases in the atmosphere with their percentage composition  Gases in the atmospherePercentage composition","images":[],"marking_scheme":"S/NGases in the atmosphere% composition1Oxygen20.5-21.52Nitrogen78-793Noble gases/Argon0.9-1.04Carbon dioxide0.03-0.05","marks":"3","difficulty":"1"},{"id":"theory>Biology>2018>6>c>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"State four characteristics of a salt marsh habitat","images":[],"marking_scheme":"- Salt marshes are coastal wetlands that are flooded and drained by salt water brought in by the tides.   -They are marshy because the soil may be composed of deep mud and peat. Peat is made of decomposing plant matter that is often several feet thick. Peat is waterlogged, root-filled, and very spongy.  -Salt marshes are frequently submerged by the tides and contain a lot of decomposing plant material, oxygen levels in the peat can be extremely low\u2014a condition called hypoxia. Hypoxia is caused by the growth of bacteria which produce the sulfurous rotten-egg smell that is often associated with marshes and mud flats.   - it is often just dead shoot stubble or root/rhizomes that are left as much of the inorganic sediment has been eroded away.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2018>6>c>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain briefly how plants are modified for anchorage in a salt marsh habitat","images":[],"marking_scheme":"Plants grow long/have numerous roots; to hold to the substratum; possess stilt roots; for anchorage.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2018>6>d>i","subject":"Biology","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"List four bacterial diseases associated with poor food hygiene.","images":[],"marking_scheme":"- Cholera  - Typhoid  - Bacteria dysentery  - Food poisoning","marks":"2","difficulty":"2"},{"id":"theory>Biology>2018>6>d>ii","subject":"Biology","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"State three effects of poor food hygiene.","images":[],"marking_scheme":"- It causes diseases  - It affects digestive organs  - It weakens the patient","marks":"2","difficulty":"1"},{"id":"theory>Biology>2018>6>e","subject":"Biology","year":"2018","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"A person was involved in a car accident and became unconscious due to excess blood loss. Explain briefly how the blood lost could be restored.","images":[],"marking_scheme":"- The victim must first be rushed to the hospital;  - Where the blood sample will be taken;  - For agglutination test;  - To know the blood group;  - Then the compatible blood is transfused to the victim.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2018>6>f","subject":"Biology","year":"2018","type":"Theory","sub_label":"f","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"State three differences between Tillage and Bush burning as far as farming practices.  TillageBush burning","images":[],"marking_scheme":"TillageBush Burning- It improves soil structure  - It does not destroy farm animals/organisms  - It aids soil aeration  - It does not cause soil erosionIt damages soil structure  It kills soil organisms  It destroy soil aeration  It causes soil erosion","marks":"2","difficulty":"2"}];